// Aceita {campanha_envio_id} direto OU {} pra varredura em lote.
// Devolve lista de envio_ids a processar.

const body = $json.body || {};
const envioEspecifico = body.campanha_envio_id;

if (envioEspecifico) {
  return [{ json: { envio_id: envioEspecifico, modo: 'single' } }];
}
return [{ json: { modo: 'batch' } }];

// Busca envio + briefing + último contato. Valida se IA está ativa.

const envio = $json;
const camp = envio.campanha;

if (!camp) return [{ json: { skip: true, reason: 'sem campanha' } }];
if (!['ativa','em_andamento'].includes(camp.status)) return [{ json: { skip: true, reason: `campanha ${camp.status}` } }];

const briefing = camp.briefing_ia || {};
if (!briefing.ia_ativa) return [{ json: { skip: true, reason: 'ia_ativa=false' } }];

return [{
  json: {
    envio_id: envio.id,
    campanha_id: envio.campanha_id,
    lead_id: envio.lead_id,
    telefone: envio.telefone,
    campanha_nome: camp.nome,
    mensagem_inicial: camp.mensagem,
    briefing,
    primeira_msg_contato_em_lock: envio.primeira_msg_contato_em,
  }
}];

// Monta prompt pra Gemini baseado no briefing + histórico

const envio = $('Validar IA ativa').item.json;
const msgs = ($json || []).slice().reverse(); // ordem cronológica

const b = envio.briefing || {};
const persona = b.persona || 'Você é um representante da GSS Saúde do Dr. Maikon Madeira (cirurgião cardíaco).';
const contexto = b.contexto || '';
const objetivo = b.objetivo || 'Qualificar interesse do lead e escalar pra humano se demonstrar interesse.';
const beneficios = Array.isArray(b.beneficios) && b.beneficios.length > 0
  ? '\n\nBenefícios:\n' + b.beneficios.map(x => `- ${x}`).join('\n')
  : '';
const objecoes = Array.isArray(b.objecoes) && b.objecoes.length > 0
  ? '\n\nObjeções comuns:\n' + b.objecoes.map(o => `- "${o.pergunta}": ${o.resposta}`).join('\n')
  : '';
const proibidas = Array.isArray(b.palavras_proibidas) && b.palavras_proibidas.length > 0
  ? `\n\nNUNCA use: ${b.palavras_proibidas.join(', ')}.`
  : '';

const kws = Array.isArray(b.handoff_keywords) ? b.handoff_keywords : ['salario','salário','valor','remuneração','remuneracao'];
const ultimaMsgContato = msgs.filter(m => !m.from_me).slice(-1)[0];
const textoUltima = (ultimaMsgContato?.text || '').toLowerCase();
const keywordMatch = kws.some(k => textoUltima.includes(k.toLowerCase()));

const systemPrompt = `${persona}\n\n${contexto}\n\nOBJETIVO: ${objetivo}\n\nMENSAGEM INICIAL QUE FOI ENVIADA:\n"${envio.mensagem_inicial || ''}"${beneficios}${objecoes}${proibidas}\n\nREGRAS:\n- Responda CURTO e NATURAL (1-2 frases preferencial, máx 3 msgs).\n- NÃO use emoji auto, NÃO use markdown/bold, NÃO use bullets.\n- Varie cumprimentos (oi/opa/e aí) - EVITE "Olá!".\n- Se pedir salário/valor/remuneração → NÃO responda valor. Escale (alerta_lead=true).\n- Se lead disser que não tem interesse → conversa_encerrada=true.\n- Se demonstrar interesse forte → alerta_lead=true.\n\nSEMPRE devolva JSON no formato:\n{ "messages": ["msg1","msg2"], "alerta_lead": boolean, "motivo_alerta": "", "conversa_encerrada": boolean }`;

const transcricao = msgs.map(m => {
  const who = m.from_me ? 'EQUIPE' : 'LEAD';
  const tag = m.message_type && m.message_type !== 'text' ? ` [${m.message_type}]` : '';
  return `${who}${tag}: ${m.text || '(sem texto)'}`;
}).join('\n');

const warn = keywordMatch ? '\n\n[ALERTA: detectamos palavra-chave de handoff na última msg. Considere alerta_lead=true.]' : '';

const userPrompt = `Conversa:\n\n${transcricao}${warn}\n\nResponda APENAS à última msg do lead. Devolva JSON.`;

return [{
  json: {
    ...envio,
    keywordMatch,
    systemPrompt,
    userPrompt,
    gemini_body: {
      systemInstruction: { parts: [{ text: systemPrompt }] },
      contents: [{ role: 'user', parts: [{ text: userPrompt }] }],
      generationConfig: {
        temperature: 0.7,
        responseMimeType: 'application/json',
        responseSchema: {
          type: 'object',
          properties: {
            messages: { type: 'array', items: { type: 'string' } },
            alerta_lead: { type: 'boolean' },
            motivo_alerta: { type: 'string' },
            conversa_encerrada: { type: 'boolean' }
          },
          required: ['messages','alerta_lead','motivo_alerta','conversa_encerrada']
        }
      }
    }
  }
}];

// Parse resposta Gemini
const envio = $('Montar prompt Gemini').item.json;
const raw = $json;
const text = raw?.candidates?.[0]?.content?.parts?.[0]?.text || '';

let parsed;
try {
  const clean = text.replace(/^```json\s*/i, '').replace(/```$/, '').trim();
  parsed = JSON.parse(clean);
} catch (e) {
  return [{ json: { ...envio, erro: 'JSON inválido Gemini', raw: text.slice(0, 300) } }];
}

return [{
  json: {
    ...envio,
    ia_messages: parsed.messages || [],
    alerta_lead: !!parsed.alerta_lead,
    motivo_alerta: parsed.motivo_alerta || '',
    conversa_encerrada: !!parsed.conversa_encerrada,
    deve_fazer_handoff: !!(envio.keywordMatch || parsed.alerta_lead),
  }
}];

// Se o lead picou uma msg nova enquanto o Gemini estava respondendo,
// o primeira_msg_contato_em mudou — aborta pra não responder desatualizado.

const envio = $('Parse resposta').item.json;
const atual = Array.isArray($json) ? $json[0] : $json;
const agoraEm = atual?.primeira_msg_contato_em;

if (agoraEm !== envio.primeira_msg_contato_em_lock) {
  return [{ json: { ...envio, abortado: true, reason: 'debounce invalidado (lead picou msg nova)' } }];
}

return [{ json: envio }];

// Busca instância que a IA usa pra responder (briefing.handoff_numero_chip
// OU primeiro chip_ids da campanha). Normaliza telefone.

const envio = $json;
if (envio.abortado) return [{ json: envio }];

const b = envio.briefing || {};
const chipId = b.handoff_numero_chip;

// Normaliza telefone pro padrão +55
function normalize(raw) {
  let d = (raw || '').replace(/\D/g, '');
  if (d.startsWith('55') && d.length > 11) d = d.slice(2);
  if (d.length < 10 || d.length > 11) return null;
  if (d.length === 10) {
    const c = parseInt(d[2], 10);
    if (c >= 6) d = d.slice(0, 2) + '9' + d.slice(2);
  }
  return '55' + d;
}

const phone = normalize(envio.telefone);
if (!phone) return [{ json: { ...envio, abortado: true, reason: 'telefone inválido' } }];

return [{ json: { ...envio, phone_normalized: phone, chip_ia_id: chipId } }];

// Dispara cada msg via Evolution com presence 'composing' + delay natural.
// NOTA: n8n node limits — pra não complicar com loop interno, enviamos
// somente a primeira msg. Se precisar mandar múltiplas, iterate external.

const envio = $('Preparar envio').item.json;
if (envio.abortado) return [{ json: envio }];

const instancia = Array.isArray($json) ? $json[0] : $json;
const instanciaNome = instancia?.nome_instancia;
if (!instanciaNome) return [{ json: { ...envio, abortado: true, reason: 'sem instância IA disponível' } }];

return [{
  json: {
    ...envio,
    instancia_nome: instanciaNome,
    primeira_msg: (envio.ia_messages && envio.ia_messages[0]) || 'Ok!',
    todas_msgs: envio.ia_messages || [],
  }
}];
